// Complete CP949 (a.k.a. UHC / "Unified Hangul Code") two-byte -> Unicode
// code point table, generated once offline from Python's authoritative
// 'cp949' codec (verified to match macOS/glibc iconv -f CP949) and frozen
// here as base64 data. Zero runtime dependency — no npm package, just data.
//
// Why this exists instead of the platform TextDecoder: Node's built-in
// TextDecoder('euc-kr') only implements the strict KS X 1001 table (~8,224
// hangul/hanja/symbol codes). Real-world Korean sites that declare
// "charset=euc-kr" almost always actually serve the Microsoft CP949
// superset, which adds ~8,824 additional precomposed Hangul syllables used
// constantly in casual/slang text (e.g. "앜ㅋㅋ"). Node's decoder silently
// mis-decodes those extra syllables into unrelated CJK characters or U+FFFD
// instead of throwing, so a plain `new TextDecoder('euc-kr')` looks like it
// works but corrupts a meaningful fraction of real titles. This table is the
// full 17,048-entry CP949 map (strict EUC-KR ∪ UHC extension), regenerate
// via: python3 -c "..." — see docs/encoding-notes.md if that's ever needed.
//
// Format: KEYS/VALS are same-length little-endian Uint16 arrays (base64),
// KEYS[i] = (leadByte << 8) | trailByte, VALS[i] = the Unicode code point,
// sorted ascending by key for binary search.

const KEYS_B64 =
  "";
const VALS_B64 =
  "";

let keys = null;
let vals = null;

function u16(base64) {
  // Buffer.from(base64, "base64") can return a view into Node's shared
  // pooled ArrayBuffer (small allocations only) with a non-zero byteOffset —
  // slice explicitly rather than reading .buffer directly, or a pooled
  // offset would silently misalign every Uint16 read.
  const buf = Buffer.from(base64, "base64");
  return new Uint16Array(buf.buffer.slice(buf.byteOffset, buf.byteOffset + buf.byteLength));
}

function ensureLoaded() {
  if (keys) return;
  keys = u16(KEYS_B64);
  vals = u16(VALS_B64);
}

function lookup(key) {
  ensureLoaded();
  let lo = 0;
  let hi = keys.length - 1;
  while (lo <= hi) {
    const mid = (lo + hi) >>> 1;
    const k = keys[mid];
    if (k === key) return vals[mid];
    if (k < key) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

// Decode a byte buffer as CP949 (EUC-KR's real-world superset). ASCII bytes
// (<0x80) pass through unchanged; two-byte sequences are looked up in the
// full table; anything unmapped or truncated falls back to U+FFFD and
// resyncs by one byte, matching TextDecoder's non-fatal replacement
// behavior so callers never see a thrown exception mid-page.
export function decodeCp949(bytes) {
  let out = "";
  let i = 0;
  const n = bytes.length;
  while (i < n) {
    const b = bytes[i];
    if (b < 0x80) {
      out += String.fromCharCode(b);
      i += 1;
      continue;
    }
    if (i + 1 < n) {
      const cp = lookup((b << 8) | bytes[i + 1]);
      if (cp >= 0) {
        out += String.fromCodePoint(cp);
        i += 2;
        continue;
      }
    }
    out += "�";
    i += 1;
  }
  return out;
}
